/**
 * Inter (Regular + Bold), subsetted to printable ASCII (letters, digits,
 * punctuation, space) plus Czech diacritics, and base64-encoded for jsPDF
 * addFileToVFS/addFont. jsPDF core fonts (Helvetica etc.) only cover
 * WinAnsi/Latin-1, which does not include Czech caron/ring characters --
 * feeding them to doc.text() with a core font silently drops or
 * mis-renders those glyphs. An earlier version of this subset only
 * requested letters+digits+diacritics and omitted punctuation entirely --
 * coordinates like "50.030568" and dates rely on ".", so that version
 * silently truncated/dropped everything after the first punctuation mark
 * jsPDF could not map to a glyph. Sourced from Google Fonts' legacy
 * subsetting endpoint (css2?family=Inter&text=...), the only public
 * endpoint that still serves raw .ttf (modern requests get woff2, which
 * jsPDF cannot consume directly) -- OFL-1.1 licensed.
 */

export const INTER_REGULAR_TTF_BASE64 =
  "";

export const INTER_BOLD_TTF_BASE64 =
  "";
